from PIL import Image
from collections import deque

img = Image.open\('/Users/yutotakemori/Downloads/kumataro.jpeg'\).convert\('RGBA'\)
pixels = img.load\(\)
w, h = img.size

# Flood fill from edges to find white background
visited = [[False]*w for _ in range\(h\)]
queue = deque\(\)

# Seed from edges - white pixels
for x in range\(w\):
    for y in [0, h-1]:
        r, g, b, a = pixels[x, y]
        if r > 230 and g > 230 and b > 230:
            queue.append\(\(x, y\)\)
            visited[y][x] = True
for y in range\(h\):
    for x in [0, w-1]:
        r, g, b, a = pixels[x, y]
        if r > 230 and g > 230 and b > 230:
            if not visited[y][x]:
                queue.append\(\(x, y\)\)
                visited[y][x] = True

# BFS
while queue:
    cx, cy = queue.popleft\(\)
    for dx, dy in [\(-1,0\),\(1,0\),\(0,-1\),\(0,1\)]:
        nx, ny = cx+dx, cy+dy
        if 0 <= nx < w and 0 <= ny < h and not visited[ny][nx]:
            r, g, b, a = pixels[nx, ny]
            if r > 215 and g > 215 and b > 215:
                visited[ny][nx] = True
                queue.append\(\(nx, ny\)\)

# Apply transparency
for y in range\(h\):
    for x in range\(w\):
        if visited[y][x]:
            r, g, b, a = pixels[x, y]
            pixels[x, y] = \(r, g, b, 0\)
        else:
            # Soft edge near background
            r, g, b, a = pixels[x, y]
            if r > 200 and g > 200 and b > 200:
                near_bg = False
                for dx, dy in [\(-1,0\),\(1,0\),\(0,-1\),\(0,1\),\(-2,0\),\(2,0\),\(0,-2\),\(0,2\)]:
                    nx2, ny2 = x+dx, y+dy
                    if 0 <= nx2 < w and 0 <= ny2 < h and visited[ny2][nx2]:
                        near_bg = True
                        break
                if near_bg:
                    brightness = r * 0.299 + g * 0.587 + b * 0.114
                    fade = min\(max\(\(brightness - 190\) / 65, 0\), 1\)
                    pixels[x, y] = \(r, g, b, int\(255 * \(1 - fade\)\)\)

img.save\('/Users/yutotakemori/new-game/smash-game/images/kumataro.png'\)
print\(f"Done: {w}x{h}"\)
PYEOF)
